import{_ as a,c as n,o as l,aN as t}from"./chunks/framework.DXgs1r1w.js";const p="/Li6Daily/assets/image.Bc7oZGLI.png",e="/Li6Daily/assets/image-1.Cj82jTSi.png",P=JSON.parse('{"title":"TCP-IP","description":"","frontmatter":{"date":"2024-08-30T15:10:02.000Z","title":"TCP-IP","outline":"deep","lastUpdated":true,"footer":true,"permalink":"/pages/b6be62","categories":["Linux","计算机网络"]},"headers":[],"relativePath":"Linux/计算机网络/TCP-IP.md","filePath":"Linux/计算机网络/TCP-IP.md","lastUpdated":1784100320000}'),i={name:"Linux/计算机网络/TCP-IP.md"};function r(d,s,c,o,b,u){return l(),n("div",null,[...s[0]||(s[0]=[t('<h1 id="tcp-ip" tabindex="-1">TCP-IP <a class="header-anchor" href="#tcp-ip" aria-label="Permalink to &quot;TCP-IP&quot;">​</a></h1><h2 id="tcp-ip四层模型介绍" tabindex="-1">TCP/IP四层模型介绍 <a class="header-anchor" href="#tcp-ip四层模型介绍" aria-label="Permalink to &quot;TCP/IP四层模型介绍&quot;">​</a></h2><p>TCP/IP协议是一系列网络协议的总和；包括：TCP，IP，UDP，ARP等，这些被称为子协议。在这些协议中，最重要、最著名的就是TCP和IP。因此，大部分网络管理员称整个协议族为“TCP/IP”它定义了电子设备如何接入互联网，以及数据如何在它们之间互相传输</p><p>IP 协议是“Internet Protocol”的缩写，主要目的是解决寻址和路由问题，以及如何在两 点间传送数据包。IP 协议使用“IP 地址”的概念来定位互联网上的每一台计算机。</p><p>​TCP 协议是“Transmission Control Protocol”的缩写，意思是“传输控制协议”，它位 于 IP 协议之上，基于 IP 协议提供可靠的、字节流形式的通信，是 HTTP 协议得以实现的基础。</p><p>​TCP/IP 协议总共有四层，就像搭积木一样，每一层需要下层的支撑，同时又支撑着上层，任何一层被抽掉都可能会导致整个协议栈坍塌。</p><p>从上到下分别四层</p><p>第一层：应用层：负责处理特定的应用程序细节，应用程序间沟通的层（HTTP）。</p><p>第二层：运输层：提供进程间的数据传输。在TCP/IP协议族中，有两个互不相同的传输协议：TCP(传输控制协议)和UDP(用户数据报协议)。</p><p>第三层：网络层：提供数据封包传送服务。在TCP/IP协议族中，网络层协议包括IP协议(网际协议)，ICMP协议(Internet互联网控制报文协议)，以及IGMP协议(Internet组管理协议)。</p><p>第四层：链路层：有时也称作数据链路层或网络接口层,通常包括操作系统中的设备驱动程序和计算机中对应的网络接口卡，负责数据帧的发送和接收。</p><p><img src="'+p+'" alt="TCP/IP四层模型" loading="lazy"></p><p>TCP/IP协议簇</p><p><img src="'+e+`" alt="TCP/IP协议簇" loading="lazy"></p><h3 id="应用层" tabindex="-1">应用层 <a class="header-anchor" href="#应用层" aria-label="Permalink to &quot;应用层&quot;">​</a></h3><ul><li>应用层的主要协议： <ul><li>HTTP（Hypertext Transfer Protocol，超文本传输协议）</li><li>HTTP（HyperText Transfer Protocol Secure，超文本传输安全协议）</li><li>FTP（File Transfer Protocol，文件传输协议）</li><li>SMTP（Simple Mail Transfer Protocol，简单邮件传输协议）</li><li>DNS（Domain Name System，地址解析协议）</li></ul></li><li>主要功能： 按照不同应用的特定要求和方式把数据传输到传输层或者接受从传输层返回的数据。实现不同应用之间的通信和数据交换，提供各种应用服务，如网页浏览、文件传输、电子邮件发送等。</li></ul><h2 id="tcp-ip-osi网络7层模型" tabindex="-1">TCP/IP OSI网络7层模型 <a class="header-anchor" href="#tcp-ip-osi网络7层模型" aria-label="Permalink to &quot;TCP/IP OSI网络7层模型&quot;">​</a></h2><p>分别是应用层、表示层、会话层、传输层、网络层、数据链路层以及物理层。</p><p>每一层负责的职能都不同，如下： • 应用层，负责给应用程序提供统一的接口； • 表示层，负责把数据转换成兼容另一个系统能识别的格式； • 会话层，负责建立、管理和终止表示层实体之间的通信会话； • 传输层，负责端到端的数据传输； • 网络层，负责数据的路由、转发、分片； • 数据链路层，负责数据的封帧和差错检测，以及 MAC 寻址； • 物理层，负责在物理网络中传输数据帧；</p><h2 id="tcp-协议详解" tabindex="-1">TCP 协议详解 <a class="header-anchor" href="#tcp-协议详解" aria-label="Permalink to &quot;TCP 协议详解&quot;">​</a></h2><h3 id="tcp-报文格式" tabindex="-1">TCP 报文格式 <a class="header-anchor" href="#tcp-报文格式" aria-label="Permalink to &quot;TCP 报文格式&quot;">​</a></h3><p>TCP 报文由<strong>首部</strong>和<strong>数据</strong>两部分组成。首部的前 20 个字节是固定的，后面可以有 4N 字节的选项字段。</p><table tabindex="0"><thead><tr><th>字段</th><th>长度</th><th>说明</th></tr></thead><tbody><tr><td>源端口</td><td>16 位</td><td>发送方端口号</td></tr><tr><td>目的端口</td><td>16 位</td><td>接收方端口号</td></tr><tr><td>序号（Seq）</td><td>32 位</td><td>本报文段所发送数据的第一个字节的序号</td></tr><tr><td>确认号（Ack）</td><td>32 位</td><td>期望收到对方下一个报文段的第一个数据字节的序号</td></tr><tr><td>数据偏移</td><td>4 位</td><td>TCP 首部长度（以 4 字节为单位）</td></tr><tr><td>保留</td><td>6 位</td><td>保留字段</td></tr><tr><td>控制位</td><td>6 位</td><td>URG、ACK、PSH、RST、SYN、FIN</td></tr><tr><td>窗口大小</td><td>16 位</td><td>接收窗口大小，用于流量控制</td></tr><tr><td>检验和</td><td>16 位</td><td>校验首部和数据</td></tr><tr><td>紧急指针</td><td>16 位</td><td>仅在 URG=1 时有效</td></tr></tbody></table><p><strong>6 个控制位说明：</strong></p><ul><li><strong>URG</strong>：紧急指针有效</li><li><strong>ACK</strong>：确认号有效（连接建立后所有报文都必须置 1）</li><li><strong>PSH</strong>：提示接收方尽快将数据交付应用层</li><li><strong>RST</strong>：重置连接</li><li><strong>SYN</strong>：同步序号，用于建立连接</li><li><strong>FIN</strong>：发送方数据发送完毕，用于释放连接</li></ul><h3 id="tcp-三次握手-建立连接" tabindex="-1">TCP 三次握手（建立连接） <a class="header-anchor" href="#tcp-三次握手-建立连接" aria-label="Permalink to &quot;TCP 三次握手（建立连接）&quot;">​</a></h3><p>TCP 建立连接的过程称为<strong>三次握手</strong>，目的是同步双方的初始序号（ISN），确保双方都有发送和接收数据的能力。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  客户端                                服务器</span></span>
<span class="line"><span>    |                                     |</span></span>
<span class="line"><span>    |  -------- SYN=1, Seq=x --------&gt;    |  第一次握手：客户端发送 SYN 包</span></span>
<span class="line"><span>    |                                     |</span></span>
<span class="line"><span>    |  &lt;--- SYN=1, ACK=1, Seq=y, ----     |  第二次握手：服务器回应 SYN+ACK</span></span>
<span class="line"><span>    |       Ack=x+1                    |</span></span>
<span class="line"><span>    |                                     |</span></span>
<span class="line"><span>    |  -------- ACK=1, Seq=x+1, -----&gt;    |  第三次握手：客户端发送 ACK 确认</span></span>
<span class="line"><span>    |       Ack=y+1                       |</span></span>
<span class="line"><span>    |                                     |</span></span>
<span class="line"><span>    |  连接建立，开始数据传输              |</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p><strong>为什么需要三次握手？</strong></p><ul><li>防止已失效的连接请求报文突然传到服务器，导致服务器资源浪费。</li><li>三次握手能确保双方确认对方的发送能力和接收能力都正常。</li></ul><h3 id="tcp-四次挥手-释放连接" tabindex="-1">TCP 四次挥手（释放连接） <a class="header-anchor" href="#tcp-四次挥手-释放连接" aria-label="Permalink to &quot;TCP 四次挥手（释放连接）&quot;">​</a></h3><p>TCP 连接是全双工的，每个方向都需要单独关闭，因此需要<strong>四次挥手</strong>。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  客户端                                服务器</span></span>
<span class="line"><span>    |                                     |</span></span>
<span class="line"><span>    |  -------- FIN=1, Seq=u --------&gt;    |  第一次挥手：客户端发送 FIN，关闭客户端到服务器的数据传送</span></span>
<span class="line"><span>    |                                     |</span></span>
<span class="line"><span>    |  &lt;----- ACK=1, Seq=v, Ack=u+1 --    |  第二次挥手：服务器收到 FIN，发 ACK 确认</span></span>
<span class="line"><span>    |                                     |</span></span>
<span class="line"><span>    |  &lt;----- FIN=1, ACK=1, Seq=w, ---    |  第三次挥手：服务器发送 FIN，关闭服务器到客户端的数据传送</span></span>
<span class="line"><span>    |       Ack=u+1                       |</span></span>
<span class="line"><span>    |                                     |</span></span>
<span class="line"><span>    |  -------- ACK=1, Seq=u+1, -----&gt;    |  第四次挥手：客户端收到 FIN，发 ACK 确认，进入 TIME_WAIT</span></span>
<span class="line"><span>    |       Ack=w+1                       |</span></span>
<span class="line"><span>    |                                     |</span></span>
<span class="line"><span>    |  等待 2MSL 后关闭                   |  服务器收到 ACK 后立即关闭</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p><strong>为什么需要 TIME_WAIT（2MSL）等待？</strong></p><ul><li>确保最后一个 ACK 能被服务器收到（如果丢失，服务器会重发 FIN）。</li><li>让本次连接内所有报文从网络中消失，防止影响下一个新连接。</li><li>MSL（Maximum Segment Lifetime）即报文最大生存时间，通常为 2 分钟。</li></ul><p><strong>为什么是四次挥手而不是三次？</strong></p><ul><li>因为 TCP 是全双工的，当一方发送 FIN 表示不再发送数据时，另一方可能还有数据需要发送。所以先回 ACK，等数据发完再发 FIN，这就导致需要四次交互。</li></ul><h3 id="tcp-状态转换" tabindex="-1">TCP 状态转换 <a class="header-anchor" href="#tcp-状态转换" aria-label="Permalink to &quot;TCP 状态转换&quot;">​</a></h3><p>TCP 连接在生命周期中会经历多种状态：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  客户端状态：                          服务器状态：</span></span>
<span class="line"><span>  CLOSED                                CLOSED</span></span>
<span class="line"><span>    | SYN_SENT                            | LISTEN</span></span>
<span class="line"><span>    |    \\                               /</span></span>
<span class="line"><span>    |     ----- SYN -----&gt;  SYN_RCVD ---</span></span>
<span class="line"><span>    |     &lt;--- SYN+ACK ---              |</span></span>
<span class="line"><span>    |    /                               |</span></span>
<span class="line"><span>  ESTABLISHED  &lt;--- ACK -------------   ESTABLISHED</span></span>
<span class="line"><span>    |                                     |</span></span>
<span class="line"><span>    | FIN_WAIT_1 -- FIN --&gt; CLOSE_WAIT    |</span></span>
<span class="line"><span>    | FIN_WAIT_2 &lt;-- ACK ---              |</span></span>
<span class="line"><span>    | TIME_WAIT  &lt;-- FIN --- LAST_ACK     |</span></span>
<span class="line"><span>    |   -- ACK --&gt;              |         |</span></span>
<span class="line"><span>    | (等待2MSL)              CLOSED      |</span></span>
<span class="line"><span>  CLOSED</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><h3 id="tcp-流量控制" tabindex="-1">TCP 流量控制 <a class="header-anchor" href="#tcp-流量控制" aria-label="Permalink to &quot;TCP 流量控制&quot;">​</a></h3><p>TCP 使用<strong>滑动窗口</strong>机制进行流量控制，防止发送方发送速率过快导致接收方来不及处理。</p><ul><li>接收方通过 TCP 首部中的<strong>窗口字段</strong>告知发送方自己当前可用的接收缓冲区大小。</li><li>发送方根据窗口大小调整发送速率，确保不会超过接收方的处理能力。</li><li>当窗口大小为 0 时，发送方停止发送，并启动<strong>持续计时器</strong>，周期性发送零窗口探测报文。</li></ul><h3 id="tcp-拥塞控制" tabindex="-1">TCP 拥塞控制 <a class="header-anchor" href="#tcp-拥塞控制" aria-label="Permalink to &quot;TCP 拥塞控制&quot;">​</a></h3><p>拥塞控制是防止过多数据注入网络，导致网络过载。TCP 使用四种算法实现拥塞控制：</p><h4 id="_1-慢启动-slow-start" tabindex="-1">1. 慢启动（Slow Start） <a class="header-anchor" href="#_1-慢启动-slow-start" aria-label="Permalink to &quot;1. 慢启动（Slow Start）&quot;">​</a></h4><ul><li>连接建立后，**拥塞窗口（cwnd）**初始为 1 个 MSS（最大报文段长度）。</li><li>每收到一个 ACK，cwnd 加倍（指数增长），直到达到<strong>慢启动阈值（ssthresh）</strong>。</li></ul><h4 id="_2-拥塞避免-congestion-avoidance" tabindex="-1">2. 拥塞避免（Congestion Avoidance） <a class="header-anchor" href="#_2-拥塞避免-congestion-avoidance" aria-label="Permalink to &quot;2. 拥塞避免（Congestion Avoidance）&quot;">​</a></h4><ul><li>当 cwnd &gt;= ssthresh 时，进入拥塞避免阶段。</li><li>每个 RTT 内 cwnd 线性增加 1 个 MSS（加法增大），而不是指数增长。</li></ul><h4 id="_3-快重传-fast-retransmit" tabindex="-1">3. 快重传（Fast Retransmit） <a class="header-anchor" href="#_3-快重传-fast-retransmit" aria-label="Permalink to &quot;3. 快重传（Fast Retransmit）&quot;">​</a></h4><ul><li>当发送方连续收到 3 个重复 ACK 时，立即重传丢失的报文段，而不必等待超时。</li><li>触发条件：接收方收到失序报文时，会立即发送重复 ACK。</li></ul><h4 id="_4-快恢复-fast-recovery" tabindex="-1">4. 快恢复（Fast Recovery） <a class="header-anchor" href="#_4-快恢复-fast-recovery" aria-label="Permalink to &quot;4. 快恢复（Fast Recovery）&quot;">​</a></h4><ul><li>触发快重传后，将 ssthresh 设为当前 cwnd 的一半，cwnd 也设为 ssthresh。</li><li>然后直接进入拥塞避免阶段，而不是慢启动。</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>拥塞窗口变化示意：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  cwnd</span></span>
<span class="line"><span>   ^</span></span>
<span class="line"><span>   |                    / 发生超时</span></span>
<span class="line"><span>   |       指数增长    /   重新慢启动</span></span>
<span class="line"><span>   |         /|\\      /</span></span>
<span class="line"><span>   |        / | \\    /</span></span>
<span class="line"><span>   |       /  |  \\  /</span></span>
<span class="line"><span>   |      /   |   \\/_________ 线性增长（拥塞避免）</span></span>
<span class="line"><span>   |     /    |   ssthresh</span></span>
<span class="line"><span>   |    /     |</span></span>
<span class="line"><span>   |   /  慢启动</span></span>
<span class="line"><span>   |  /</span></span>
<span class="line"><span>   +--------------------------------------&gt; 时间</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><h3 id="tcp-与-udp-对比" tabindex="-1">TCP 与 UDP 对比 <a class="header-anchor" href="#tcp-与-udp-对比" aria-label="Permalink to &quot;TCP 与 UDP 对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>TCP</th><th>UDP</th></tr></thead><tbody><tr><td>连接性</td><td>面向连接</td><td>无连接</td></tr><tr><td>可靠性</td><td>可靠（确认、重传机制）</td><td>不可靠（尽最大努力交付）</td></tr><tr><td>顺序性</td><td>保证数据顺序</td><td>不保证数据顺序</td></tr><tr><td>速度</td><td>较慢</td><td>较快</td></tr><tr><td>首部开销</td><td>20-60 字节</td><td>8 字节</td></tr><tr><td>适用场景</td><td>文件传输、网页浏览、邮件</td><td>视频直播、语音通话、DNS查询</td></tr><tr><td>流量控制</td><td>有（滑动窗口）</td><td>无</td></tr><tr><td>拥塞控制</td><td>有</td><td>无</td></tr></tbody></table><h3 id="常见面试问题" tabindex="-1">常见面试问题 <a class="header-anchor" href="#常见面试问题" aria-label="Permalink to &quot;常见面试问题&quot;">​</a></h3><p><strong>Q1：为什么 TCP 是可靠的？</strong></p><ul><li>确认应答机制：每个报文都需要 ACK 确认</li><li>超时重传：发送方在指定时间内未收到 ACK 则重传</li><li>序号机制：保证数据有序到达</li><li>检验和：检测数据在传输中的错误</li><li>流量控制和拥塞控制：防止数据丢失</li></ul><p><strong>Q2：TCP 粘包/拆包问题</strong></p><ul><li>粘包：发送方多次发送的数据被接收方一次性接收</li><li>拆包：发送方一次发送的数据被接收方分多次接收</li><li>原因：TCP 是流式协议，没有消息边界</li><li>解决方案：定长消息、分隔符、消息头+消息体（长度前缀）</li></ul>`,61)])])}const m=a(i,[["render",r]]);export{P as __pageData,m as default};
